#include <stdio.h>
#include <string.h>

int is_cool_number(char *num) {
    int sum = 0;
    for (int i = 0; i < strlen(num); i++) {
        sum += num[i] - '0';
    }
    for (int mask = 1; mask < (1 << strlen(num)); mask++) {
        int selected_sum = 0;
        for (int i = 0; i < strlen(num); i++) {
            if ((mask & (1 << i)) != 0) {
                selected_sum += num[i] - '0';
            }
        }
        if (__builtin_popcount(mask) <= 3) {
            int product = (sum - selected_sum) * selected_sum;
            if (product % atoi(num) == 0) {
                return 1;
            }
        }
    }
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char num[1001];
        scanf("%s", num);
        int N = atoi(num);
        int lower = N;
        while (!is_cool_number(num)) {
            lower--;
            sprintf(num, "%d", lower);
        }
        int upper = N + 1;
        sprintf(num, "%d", upper);
        while (!is_cool_number(num)) {
            upper++;
            sprintf(num, "%d", upper);
        }
        printf("%d %d\n", lower, upper);
    }
    return 0;
}

