import java.util.Scanner;
public class Main {
    public static boolean is_cool_number(String num) {
        int sum = 0;
        for (char c : num.toCharArray()) {
            sum += c - '0';
        }
        for (int mask = 1; mask < (1 << num.length()); mask++) {
            int selected_sum = 0;
            for (int i = 0; i < num.length(); i++) {
                if ((mask & (1 << i)) != 0) {
                    selected_sum += num.charAt(i) - '0';
                }
            }
            if (Integer.bitCount(mask) <= 3) {
                int product = (sum - selected_sum) * selected_sum;
                if (product % Integer.parseInt(num) == 0) {
                    return true;
                }
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            String num = scanner.next();
            int N = Integer.parseInt(num);
            int lower = N;
            while (!is_cool_number(num)) {
                lower--;
                num = String.valueOf(lower);
            }
            int upper = N + 1;
            num = String.valueOf(upper);
            while (!is_cool_number(num)) {
                upper++;
                num = String.valueOf(upper);
            }
            System.out.println(lower + " " + upper);
        }
    }
}

