function is_cool_number(num) {
    let sum = 0;
    for (let i = 0; i < num.length; i++) {
        sum += +num[i];
    }
    for (let mask = 1; mask < (1 << num.length); mask++) {
        let selected_sum = 0;
        for (let i = 0; i < num.length; i++) {
            if ((mask & (1 << i)) != 0) {
                selected_sum += +num[i];
            }
        }
        if (countBits(mask) <= 3) {
            let product = (sum - selected_sum) * selected_sum;
            if (product % +num == 0) {
                return true;
            }
        }
    }
    return false;
}

function countBits(n) {
    let count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}
